 36	
 37	import {
 38	  removeCredential,
 39	  removeSecretObject,
 40	  updateSecretName,
 41	  updateSSHKeyObject,
 42	} from './sshkey-utils';
 43	
 44	type SSHKeyProps = {
 45	  template: V1Template;
 46	};
 47	
 48	const SSHKey: FC<SSHKeyProps> = ({ template }) => {
 49	  const { t } = useKubevirtTranslation();
 50	  const { createModal } = useModal();
 51	  const { isTemplateEditable } = useEditTemplateAccessReview(template);
 52	  const vm = getTemplateVirtualMachineObject(template);
 53	
 54	  const vmAttachedSecretName = useMemo(() => getVMSSHSecretName(vm), [vm]);
 55	
 56	  const secretToCreate: IoK8sApiCoreV1Secret = useMemo(
 57	    () => template?.objects?.find((obj) => obj.kind === SecretModel.kind),
 58	    [template.objects],
 59	  );
 60	
 61	  const initialSSHDetails = useMemo(
 62	    () => getInitialSSHDetails({ secretToCreate, sshSecretName: vmAttachedSecretName }),
 63	    [vmAttachedSecretName, secretToCreate],
 64	  );
 65	
 66	  const onSubmit = (sshDetails: SSHSecretDetails) => {
 67	    const { secretOption, sshPubKey, sshSecretName } = sshDetails;
 68	
 69	    if (isEqualObject(sshDetails, initialSSHDetails)) {
 70	      return Promise.resolve();
 71	    }
 72	
 73	    const newTemplate = produce(template, (draftTemplate) => {
 74	      removeSecretObject(draftTemplate, initialSSHDetails.sshSecretName);
 75	
 76	      if (
 77	        secretOption === SecretSelectionOption.none &&
 78	        initialSSHDetails.secretOption !== SecretSelectionOption.none
 79	      ) {
 80	        removeCredential(draftTemplate, initialSSHDetails.sshSecretName);
 81	      }
 82	
 83	      if (
 84	        secretOption === SecretSelectionOption.useExisting &&
 85	        initialSSHDetails.sshSecretName !== sshSecretName &&
 86	        !isEmpty(sshSecretName)
 87	      ) {
 88	        updateSecretName(draftTemplate, sshSecretName);
 89	      }
 90	
 91	      if (
 92	        secretOption === SecretSelectionOption.addNew &&
 93	        !isEmpty(sshPubKey) &&
 94	        !isEmpty(sshSecretName)
 95	      ) {
 96	        updateSSHKeyObject(
 97	          draftTemplate,
 98	          sshPubKey,
 99	          initialSSHDetails.sshSecretName,
100	          sshSecretName,
101	        );
102	      }
103	    });
104	
105	    return k8sUpdate({
106	      data: newTemplate,
107	      model: TemplateModel,
108	      name: getName(newTemplate),
109	      ns: getNamespace(newTemplate),
110	    });
111	  };
112	
113	  return (
114	    <VirtualMachineDescriptionItem
115	      descriptionData={
116	        <Stack hasGutter>
117	          <div data-test="ssh-popover">
118	            <Text component={TextVariants.p}>{t('Select an available secret')}</Text>
119	          </div>
120	          <SecretNameLabel secretName={vmAttachedSecretName} />
121	        </Stack>
122	      }
123	      descriptionHeader={
124	        <Flex className="vm-description-item__title">
125	          <FlexItem>
126	            <Title headingLevel="h2">
127	              {t('Public SSH key')} {<LinuxLabel />}
128	            </Title>
129	          </FlexItem>
130	          <FlexItem>
131	            <Button
132	              onClick={() =>
133	                createModal((modalProps) => (
134	                  <SSHSecretModal
135	                    {...modalProps}
136	                    initialSSHSecretDetails={initialSSHDetails}
137	                    isTemplate
138	                    namespace={getNamespace(template)}
139	                    onSubmit={onSubmit}
140	                  />
141	                ))
142	              }
143	              isDisabled={!isTemplateEditable}
144	              isInline
145	              type="button"
146	              variant={ButtonVariant.link}
147	            >
148	              {t('Edit')}
149	              <PencilAltIcon className="co-icon-space-l pf-v6-c-button-icon--plain" />
150	            </Button>
151	          </FlexItem>
152	        </Flex>
153	      }
154	    />
155	  );
156	};
157	
158	export default SSHKey;

